class Solution:
    def kthPalindrome(self, queries, intLength):
        half_len = (intLength + 1) // 2
        start = 10 ** (half_len - 1)
        count = 9 * start
        result = []
        for k in queries:
            if k > count:
                result.append(-1)
            else:
                half = start + k - 1
                s = str(half)
                if intLength % 2 == 0:
                    full = s + s[::-1]
                else:
                    full = s + s[-2::-1]
                result.append(int(full))
        return result

