var kthPalindrome = function(queries, intLength) {
    const halfLen = Math.floor((intLength + 1) / 2);
    const start = Math.pow(10, halfLen - 1);
    const count = 9 * start;
    const result = [];
    for (const k of queries) {
        if (k > count) {
            result.push(-1);
        } else {
            const halfNum = start + k - 1;
            const s = String(halfNum);
            let full;
            if (intLength % 2 === 0) {
                full = s + s.split('').reverse().join('');
            } else {
                full = s + s.slice(0, -1).split('').reverse().join('');
            }
            result.push(Number(full));
        }
    }
    return result;
};
